Method.Source:
/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormEventHandler(formStr(InventAgingStorageDetails), FormEventType::Initialized)]
public static void inventagingstoragedetails_oninitialized(xformrun sender, formeventargs e)
{        
    str                             dimValueControl; 
    FormStringControl               dimensionFormControl,period6,period7,period8;
    DimensionHierarchy              dimensionHierarchy;
    DimensionHierarchyLevel         dimensionHierarchyLevel;
    DimensionAttribute              dimAttribute;
    InventAgingStorage              inventAgingStorage = sender.args().record();

    if(inventAgingStorage.ViewInventBatchId)
    {
        select firstonly RecId from dimensionHierarchy
            where dimensionHierarchy.Name == inventAgingStorage.DimensionSetName;

        while select Level from dimensionHierarchyLevel
            where dimensionHierarchyLevel.DimensionHierarchy == dimensionHierarchy.RecId
        join Name from dimAttribute
            where dimAttribute.RecId == dimensionHierarchyLevel.DimensionAttribute
        {
            dimValueControl = strFmt("InventAgingTmp_DimensionValues_%1",dimensionHierarchyLevel.level);
            dimensionFormControl = sender.design().controlName(dimValueControl);
            dimensionformcontrol.label(dimAttribute.Name);
            dimensionformcontrol.visible(true);
        }

        period6 =  sender.design().controlName('period6');
        period6.label(strFmt('@SYS4002693', '5'));
        period6.text(strFmt("%1 - %2 %3", inventAgingStorage.IntervalDaysFour + 1, inventAgingStorage.IntervalDaysFive, '@SYS4006426'));

        period7 =  sender.design().controlName('period7');
        Period7.label(strFmt('@SYS4002693', '6'));
        period7.text(strFmt("%1 - %2 %3", inventAgingStorage.IntervalDaysFive + 1, inventAgingStorage.IntervalDaysSix, '@SYS4006426'));

        period7 =  sender.design().controlName('period8');
        Period7.label(strFmt('@SYS4002693', '7'));
        period7.text(strFmt("%1 + %2", inventAgingStorage.IntervalDaysSix, '@SYS4006425'));

    }
}
